#define BLOCK_SIZE 16

__kernel void lud_diagonal(__global float* a, __local float* temp, const int size, const int offset) {
    int i = get_global_id(0);
    int j, k;

    if (i >= BLOCK_SIZE) return;

    int global_i = offset + i;

    // Upper triangle part of diagonal block
    for (j = i; j < BLOCK_SIZE; j++) {
        int global_j = offset + j;
        float sum = 0.0f;
        for (k = 0; k < i; k++) {
            sum += a[global_i * size + offset + k] * a[(offset + k) * size + global_j];
        }
        a[global_i * size + global_j] -= sum;
    }

    float diag = a[global_i * size + global_i];
    float inv_diag = 1.0f / diag;

    // Lower triangle part of diagonal block
    for (j = i + 1; j < BLOCK_SIZE; j++) {
        int global_j = offset + j;
        float sum = 0.0f;
        for (k = 0; k < i; k++) {
            sum += a[global_j * size + offset + k] * a[(offset + k) * size + global_i];
        }
        a[global_j * size + global_i] = (a[global_j * size + global_i] - sum) * inv_diag;
    }
}

__kernel void lud_perimeter(__global float* a, __local float* temp_top, __local float* temp_left, __local float* temp_div, const int size, const int offset) {
    int idx = get_global_id(0);
    int total_chunks = (size - offset - BLOCK_SIZE) / BLOCK_SIZE;

    if (idx >= 2 * total_chunks) return;

    int chunk_idx;
    int is_upper; // 0 for lower (left), 1 for upper (top)

    if (idx < total_chunks) {
        chunk_idx = idx;
        is_upper = 1;
    } else {
        chunk_idx = idx - total_chunks;
        is_upper = 0;
    }

    int i, j, k;
    int global_row_start, global_col_start;

    if (is_upper) {
        // Process Top perimeter blocks (Right of diagonal)
        global_row_start = offset;
        global_col_start = offset + BLOCK_SIZE * (chunk_idx + 1);

        // Load temp_top from diagonal block row
        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                temp_top[i * BLOCK_SIZE + j] = a[(offset + i) * size + (global_col_start + j)];
            }
        }

        // Compute
        for (i = 0; i < BLOCK_SIZE; i++) {
            int r = offset + i;
            for (j = 0; j < BLOCK_SIZE; j++) {
                int c = global_col_start + j;
                float sum = 0.0f;
                for (k = 0; k < i; k++) {
                    sum += a[r * size + (offset + k)] * temp_top[k * BLOCK_SIZE + j];
                }
                a[r * size + c] -= sum;
            }
        }
    } else {
        // Process Left perimeter blocks (Below diagonal)
        global_row_start = offset + BLOCK_SIZE * (chunk_idx + 1);
        global_col_start = offset;

        // Load temp_left from diagonal block column
        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                temp_left[i * BLOCK_SIZE + j] = a[(global_row_start + i) * size + (offset + j)];
            }
        }

        // Load divisor row (diagonal elements) into temp_div
        for (j = 0; j < BLOCK_SIZE; j++) {
            temp_div[j] = a[(offset + j) * size + (offset + j)];
        }

        // Compute
        for (i = 0; i < BLOCK_SIZE; i++) {
            int r = global_row_start + i;
            for (j = 0; j < BLOCK_SIZE; j++) {
                int c = offset + j;
                float sum = 0.0f;
                for (k = 0; k < j; k++) {
                    sum += temp_left[i * BLOCK_SIZE + k] * a[(offset + k) * size + c];
                }
                float val = (a[r * size + c] - sum) / temp_div[j];
                a[r * size + c] = val;
            }
        }
    }
}

__kernel void lud_internal(__global float* a, __local float* temp_top, __local float* temp_left, const int size, const int offset) {
    int gx = get_global_id(0);
    int gy = get_global_id(1);

    int total_chunks = (size - offset - BLOCK_SIZE) / BLOCK_SIZE;

    if (gx >= total_chunks || gy >= total_chunks) return;

    int i, j, k;

    int global_row_start = offset + BLOCK_SIZE * (gy + 1);
    int global_col_start = offset + BLOCK_SIZE * (gx + 1);

    // Load Top block (from the row of diagonal block)
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            temp_top[i * BLOCK_SIZE + j] = a[(offset + i) * size + (global_col_start + j)];
        }
    }

    // Load Left block (from the column of diagonal block)
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            temp_left[i * BLOCK_SIZE + j] = a[(global_row_start + i) * size + (offset + j)];
        }
    }

    // Compute internal block update
    for (i = 0; i < BLOCK_SIZE; i++) {
        int r = global_row_start + i;
        for (j = 0; j < BLOCK_SIZE; j++) {
            int c = global_col_start + j;
            float sum = 0.0f;
            for (k = 0; k < BLOCK_SIZE; k++) {
                sum += temp_left[i * BLOCK_SIZE + k] * temp_top[k * BLOCK_SIZE + j];
            }
            a[r * size + c] -= sum;
        }
    }
}
